 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    InvB = 1 	# Second Mapping used in inverse direction
    MapA = 	# First component Mapping
       Begin SplineMap 	# Map using a bi-cubic spline
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          KX = 0 	# Polynomial order in X direction
          KY = 0 	# Polynomial order in Y direction
          NX = 0 	# No. of coeffs in X direction
          NY = 0 	# No. of coeffs in Y direction
       End SplineMap
    MapB = 	# Second component Mapping
       Begin SplineMap 	# Map using a bi-cubic spline
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          KX = 0 	# Polynomial order in X direction
          KY = 0 	# Polynomial order in Y direction
          NX = 0 	# No. of coeffs in X direction
          NY = 0 	# No. of coeffs in Y direction
       End SplineMap
 End CmpMap
